import subprocess, json, os, re, sys
print("=== PHASE 1 — LIVE PRODUCTION ALIGNMENT ===\n")

print("--- GitHub HEAD ---")
local_sha = subprocess.run(['git','rev-parse','HEAD'], capture_output=True, text=True).stdout.strip()
print(f"local_sha={local_sha}")

try:
    gh = subprocess.run(['curl','-s','https://api.github.com/repos/ibb142/rork-global-real-estate-invest/git/refs/heads/main','--max-time','10'], capture_output=True, text=True, check=True)
    gh_data = json.loads(gh.stdout)
    gh_sha = gh_data.get('object',{}).get('sha','?')
    print(f"github_sha={gh_sha}")

    runs = subprocess.run(['curl','-s','https://api.github.com/repos/ibb142/rork-global-real-estate-invest/actions/runs?per_page=3','--max-time','10'], capture_output=True, text=True, check=True)
    runs_data = json.loads(runs.stdout)
    for r in runs_data.get('workflow_runs',[]):
        print(f"run={r.get('name')} | {r.get('status')}/{r.get('conclusion')} | id={r.get('id')} | {r.get('created_at')}")
except Exception as e:
    print(f"github_error={e}")

print("\n--- Backend /health ---")
try:
    health = subprocess.run(['curl','-s','https://api.ivxholding.com/health','--max-time','10'], capture_output=True, text=True, check=True)
    h = json.loads(health.stdout)
    print(f"status={h.get('status','?')} sha={h.get('commit','?')[:12]} boot={h.get('bootTime','?')} routes={len(h.get('routes',[]))}")
except Exception as e:
    print(f"backend_error={e}")

print("\n--- Landing Page ---")
try:
    landing = subprocess.run(['curl','-s','-o','/dev/null','-D','-','https://ivxholding.com','--max-time','15'], capture_output=True, text=True, check=True)
    lines = landing.stdout.split('\n')
    for line in lines:
        l = line.rstrip('\r')
        if l.startswith('HTTP') or l.lower().startswith('last-modified') or l.lower().startswith('etag') or l.lower().startswith('content-length') or l.lower().startswith('cache-control'):
            print(l)
except Exception as e:
    print(f"landing_error={e}")

print("\n--- Chat Frontend ---")
try:
    chat = subprocess.run(['curl','-s','-o','/dev/null','-D','-','https://chat.ivxholding.com','--max-time','15'], capture_output=True, text=True, check=True)
    for line in chat.stdout.split('\n'):
        l = line.rstrip('\r')
        if l.startswith('HTTP') or l.lower().startswith('cf-cache') or l.lower().startswith('last-modified'):
            print(l)
except Exception as e:
    print(f"chat_error={e}")

print("\n--- APK ---")
apk_path = '/home/user/rork-app/expo/android/app/build/outputs/apk/release/app-release.apk'
if os.path.exists(apk_path):
    size = subprocess.run(['du','-h',apk_path], capture_output=True, text=True).stdout.split()[0]
    sha = subprocess.run(['sha256sum',apk_path], capture_output=True, text=True).stdout.split()[0]
    mtime = subprocess.run(['stat','-c','%y',apk_path], capture_output=True, text=True).stdout.strip()
    print(f"exists: yes")
    print(f"size: {size}")
    print(f"sha256: {sha}")
    print(f"mtime: {mtime}")
    try:
        badging = subprocess.run(['aapt','dump','badging',apk_path], capture_output=True, text=True, check=True).stdout
        for line in badging.split('\n')[:5]:
            print(line)
    except Exception as e:
        print(f"aapt_error={e}")
else:
    print("exists: NO")

print("\n--- Environment Variables (filtered) ---")
for key in sorted(os.environ):
    if key.startswith(('EXPO_','SUPABASE_','IVX_','GITHUB_','RENDER_','AWS_')):
        print(f"{key}=REDACTED")

print("\n--- Available Tools ---")
for tool in ['aws','adb','emulator','ffmpeg','playwright','bun']:
    result = subprocess.run(['which',tool], capture_output=True, text=True)
    print(f"{tool}: {'yes' if result.returncode==0 else 'no'}")
try:
    docker = subprocess.run(['docker','--version'], capture_output=True, text=True, check=True).stdout.strip()
    print(docker)
except:
    print("docker: no")
PYEOF

