    except Exception as e:
        print(f"members table error: {e}")
        results["members_table"] = {"error": str(e)}
else:
    print("SUPABASE_SERVICE_ROLE_KEY not available — skipping direct members table query")
    results["members_table"] = {"skipped": "no service role key"}

# 5. Query profiles table
print("\n--- Profiles Table Direct Query ---")
if SERVICE_KEY and user_id:
