        db_headers = {"Authorization": f"Bearer {SERVICE_KEY}", "apikey": SERVICE_KEY, "Content-Type": "application/json"}
        profiles_res = requests.get(f"{SUPABASE_URL}/rest/v1/profiles", headers=db_headers, params={"id":"eq."+user_id,"select":"id,email,first_name,last_name,phone,created_at"}, timeout=15)
        profiles = profiles_res.json()
